## 11. Quick reference for Claude Code

When extending Hausmeister, follow these rules:

1. **Backgrounds** are `--background` / `--card` / `--muted` — never pure black.
2. **Text** is `--foreground` / `--muted-foreground` — never pure white.
3. **CTAs** are olive → faded-yellow on hover, square, mono uppercase.
4. **Headings** are JetBrains Mono 800 with tight `-0.02em` tracking.
5. **Section labels** use the `.stamp` class — rotate, border, uppercase.
6. **Cards** are sharp (radius ~2px), 1px borders, optional offset shadow
   in `--olive-deep` for "printed poster" emphasis.
7. **Copy** is dry, bureaucratic, mostly English with German nouns sprinkled
   in (Regel, Komposthaufen, Hausordnung, Mülltonne…).
8. **Motion** is mechanical: linear ticker, slow flicker, hover color swap,
   small arrow nudge. No springs, no parallax.
9. **Icons** are typographic glyphs (`✶ ≈ ☞ § № ▌ →`), not icon libraries.
10. **Never** use purple, gradients into pink, glassmorphism, or pill buttons.

// HAUSMEISTER — projector /wall + Tagesbericht.
// English-first copy with sprinkled German nouns. Spec-aligned aesthetic:
// olive accents, faded-yellow Aushang frames, 2px ticker borders, scanlines,
// QR card with offset shadow.

// ─────────────────────────────────────────────────────────────
// /wall — projector live feed (1280×720)
// ─────────────────────────────────────────────────────────────
function ScreenWall() {
  const wall = window.WALL_FEED || [];
  const scraps = wall.filter(w => w.type === "scrap");

  // Ticker items — duplicate so the loop is seamless
  const tickerItems = [
    "247 scraps logged",
    "31 purged for safety",
    "19 marked langweilig",
    "next Tagesbericht 14:00",
    "T-22:13 to submission",
    "Hausmeister leaves SUN 14:01",
  ];

  return (
    <div className="hm-sans hm-screen" style={{
      background: "var(--ink)", color: "var(--bone)",
      width: "100%", height: "100%", display: "flex", flexDirection: "column",
    }}>
      {/* warning band */}
      <div className="hm-warning-band" />

      {/* masthead */}
      <div style={{ padding: "20px 36px 16px", borderBottom: "2px solid var(--olive)", display: "flex", alignItems: "baseline", justifyContent: "space-between" }}>
        <div style={{ display: "flex", alignItems: "baseline", gap: 18 }}>
          <span className="hm-dot" style={{ width: 12, height: 12, alignSelf: "center" }} />
          <span className="hm-display" style={{ fontSize: 44, lineHeight: 1, letterSpacing: "-0.03em" }}>
            HAUSMEISTER
          </span>
          <span className="hm-stamp-label" style={{ color: "var(--muted-foreground)", fontSize: 11 }}>
            /wall · live feed
          </span>
        </div>
        <div style={{ display: "flex", gap: 18, alignItems: "baseline" }}>
          <span className="hm-stamp-label" style={{ color: "var(--muted-foreground)", fontSize: 11 }}>
            247 logged · 61 on wall
          </span>
          <span className="hm-stamp-label" style={{ color: "var(--olive)", fontSize: 12 }}>
            ● SAT 13:47
          </span>
        </div>
      </div>

      {/* Two-column body */}
      <div style={{ flex: 1, display: "grid", gridTemplateColumns: "1.25fr 1fr", overflow: "hidden" }}>
        {/* LEFT — incoming scraps */}
        <div style={{ borderRight: "2px solid var(--olive)", padding: "16px 26px", overflow: "hidden", display: "flex", flexDirection: "column", gap: 12 }}>
          <div className="hm-stamp-label" style={{ color: "var(--muted-foreground)" }}>
            ☞ Incoming · live from the Komposthaufen
          </div>
          <div style={{ flex: 1, display: "flex", flexDirection: "column", gap: 10 }}>
            {scraps.slice(0, 4).map((s, i) => (
              <div key={i} style={{
                background: "var(--card)",
                border: "1px solid var(--border)",
                padding: "12px 16px",
                position: "relative",
              }}>
                <div style={{ display: "flex", alignItems: "baseline", gap: 10, marginBottom: 6 }}>
                  <span className="hm-display" style={{ fontSize: 14, color: "var(--olive)" }}>{s.handle}</span>
                  <span className="hm-stamp-label" style={{ color: "var(--muted-foreground)" }}>· SAT {s.t}</span>
                  <span style={{ flex: 1 }} />
                  <span className="hm-stamp-label" style={{ color: "var(--muted-foreground)" }}>score</span>
                  <span className="hm-display" style={{ fontSize: 18, color: "var(--bone)" }}>{s.score}<span style={{ color: "var(--muted-foreground)", fontSize: 12 }}>/10</span></span>
                </div>
                <div style={{ fontSize: 17, lineHeight: 1.4, color: "var(--bone)" }}>
                  {s.body}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* RIGHT — Hausmeister speaks + a Hausregel + QR */}
        <div style={{ padding: "16px 26px", overflow: "hidden", display: "flex", flexDirection: "column", gap: 14 }}>
          <div className="hm-stamp-label" style={{ color: "var(--muted-foreground)" }}>
            ☞ Der Hausmeister spricht
          </div>

          {/* big quote — bone block */}
          <div style={{
            background: "var(--bone)",
            color: "var(--ink)",
            padding: "16px 20px",
            border: "2px solid var(--olive)",
            position: "relative",
          }}>
            <div className="hm-stamp-label" style={{ color: "var(--olive-deep)", marginBottom: 8 }}>
              In response to: "what's table 14 doing?"
            </div>
            <div style={{ fontSize: 22, lineHeight: 1.35, fontFamily: "JetBrains Mono, monospace", fontWeight: 500 }}>
              Table 14 has had their first <span style={{ background: "var(--yellow-faded)", padding: "0 4px" }}>"we should pivot"</span>, which is hackathon-Latin for <span style={{ fontStyle: "italic" }}>"we are out, but with style"</span>.
            </div>
          </div>

          {/* a Hausregel + QR */}
          <div style={{ display: "grid", gridTemplateColumns: "1fr auto", gap: 14, alignItems: "stretch" }}>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              <div style={{ display: "flex", gap: 12, alignItems: "stretch" }}>
                <div className="hm-display" style={{
                  fontSize: 28, color: "var(--ink)", background: "var(--olive)",
                  padding: "8px 12px", lineHeight: 1, alignSelf: "stretch",
                  display: "flex", alignItems: "center", letterSpacing: "-0.02em",
                }}>
                  §19
                </div>
                <div style={{ flex: 1, fontSize: 15, lineHeight: 1.4, padding: "6px 0" }}>
                  CORS errors are typos. Always. Forever. Look again.
                  <div className="hm-stamp-label" style={{ color: "var(--muted-foreground)", marginTop: 4 }}>
                    NEU · derived from lampe-90 · 02:18
                  </div>
                </div>
              </div>

              {/* Voice indicator */}
              <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "6px 0" }}>
                <div style={{
                  width: 32, height: 32, background: "var(--olive)",
                  display: "flex", alignItems: "center", justifyContent: "center",
                }}>
                  <div style={{ display: "flex", gap: 2, alignItems: "center", height: 18 }}>
                    {[6, 14, 10, 18, 8].map((h, i) => (
                      <div key={i} style={{ width: 2, height: h, background: "var(--ink)" }} />
                    ))}
                  </div>
                </div>
                <div className="hm-stamp-label" style={{ color: "var(--muted-foreground)" }}>
                  speaking · TTS · 8.4s
                </div>
              </div>

              {/* Lower scrap */}
              <div style={{ marginTop: 4, borderTop: "1px solid var(--border)", paddingTop: 10 }}>
                <div className="hm-stamp-label" style={{ color: "var(--muted-foreground)", marginBottom: 4 }}>
                  ☞ just overheard
                </div>
                <div style={{ fontSize: 13, lineHeight: 1.45, color: "var(--muted-foreground)", fontStyle: "italic" }}>
                  "my cofounder just used the word 'moat' and i felt my soul leave my body."
                  <span className="hm-display" style={{ color: "var(--olive)", fontStyle: "normal", fontSize: 12, marginLeft: 6 }}>
                    muelltonne-15
                  </span>
                </div>
              </div>
            </div>

            {/* QR offset-shadow card */}
            <div style={{ width: 130 }}>
              <div className="hm-shadow-card" style={{ width: 130, height: 130, padding: 10, display: "flex", alignItems: "center", justifyContent: "center" }}>
                <QRPlaceholder size={108} />
              </div>
              <div className="hm-stamp-label" style={{ marginTop: 14, color: "var(--muted-foreground)", fontSize: 9, textAlign: "center" }}>
                scan to compost
              </div>
              <div className="hm-stamp-label" style={{ color: "var(--stamp-red)", fontSize: 9, textAlign: "center", marginTop: 2 }}>
                Akte №047-K
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* bottom ticker — full bleed olive border */}
      <div style={{
        borderTop: "2px solid var(--olive)",
        borderBottom: "2px solid var(--olive)",
        background: "var(--card)",
        overflow: "hidden",
        position: "relative",
        height: 38,
        display: "flex",
        alignItems: "center",
      }}>
        <div className="hm-ticker-track" style={{ whiteSpace: "nowrap", fontFamily: "JetBrains Mono, monospace", fontSize: 13, letterSpacing: "0.12em", color: "var(--bone)" }}>
          {[...tickerItems, ...tickerItems].map((t, i) => (
            <span key={i} style={{ display: "inline-flex", alignItems: "center", padding: "0 24px", gap: 18 }}>
              <span style={{ color: "var(--olive)" }}>▌</span>
              <span>{t}</span>
            </span>
          ))}
        </div>
      </div>
    </div>
  );
}

// Simple QR placeholder — bone bg, ink modules
function QRPlaceholder({ size = 108 }) {
  // 21×21 grid pseudo-pattern
  const cells = [];
  const rng = (i, j) => ((i * 37 + j * 19 + i * j * 3) % 7) < 3;
  for (let i = 0; i < 21; i++) {
    for (let j = 0; j < 21; j++) {
      const corner = (i < 7 && j < 7) || (i < 7 && j > 13) || (i > 13 && j < 7);
      const isFinder = corner && (
        (i === 0 || i === 6 || j === 0 || j === 6) ||
        ((i >= 2 && i <= 4) && (j >= 2 && j <= 4)) ||
        // mirror finder logic for top-right and bottom-left
        ((i < 7 && j > 13) && (i === 0 || i === 6 || j === 14 || j === 20 || ((i >= 2 && i <= 4) && (j >= 16 && j <= 18)))) ||
        ((i > 13 && j < 7) && (i === 14 || i === 20 || j === 0 || j === 6 || ((i >= 16 && i <= 18) && (j >= 2 && j <= 4))))
      );
      const fill = corner ? isFinder : rng(i, j);
      cells.push({ i, j, fill });
    }
  }
  const cell = size / 21;
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} style={{ background: "var(--bone)" }}>
      {cells.map((c, k) => c.fill && (
        <rect key={k} x={c.j * cell} y={c.i * cell} width={cell} height={cell} fill="var(--ink)" />
      ))}
    </svg>
  );
}

// ─────────────────────────────────────────────────────────────
// Tagesbericht — daily report
// ─────────────────────────────────────────────────────────────
function ScreenTagesbericht() {
  const r = window.TAGESBERICHT;
  return (
    <div className="hm-sans hm-screen" style={{ background: "var(--ink)", color: "var(--bone)", padding: "0", overflow: "hidden", display: "flex", flexDirection: "column" }}>
      {/* header */}
      <div style={{ background: "var(--card)", borderBottom: "2px solid var(--olive)", padding: "22px 36px" }}>
        <div style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between" }}>
          <div>
            <div className="hm-stamp-label" style={{ color: "var(--muted-foreground)", fontSize: 11 }}>
              Verfahren · internal · do not forward
            </div>
            <h1 className="hm-display" style={{ fontSize: 56, margin: "8px 0 4px", lineHeight: 0.92, letterSpacing: "-0.03em" }}>
              Tagesbericht
            </h1>
            <div className="hm-stamp-label" style={{ fontSize: 12, color: "var(--muted-foreground)" }}>
              No. 02 · {r.date}
            </div>
          </div>
          <div style={{ textAlign: "right" }}>
            <span className="hm-stamp">Bearbeitet</span>
            <div className="hm-stamp-label" style={{ color: "var(--muted-foreground)", marginTop: 12, fontSize: 9 }}>
              Generated · LLM<br/>
              Corpus slice: FRI 18:00 → SAT 10:00
            </div>
          </div>
        </div>
      </div>

      {/* body */}
      <div className="hm-scroll" style={{ flex: 1, padding: "28px 36px", display: "grid", gridTemplateColumns: "1.4fr 1fr", gap: 40, overflow: "auto" }}>
        {/* left: prose sections */}
        <div>
          <div style={{ fontSize: 18, lineHeight: 1.5, marginBottom: 24, fontStyle: "italic", borderLeft: "3px solid var(--olive)", paddingLeft: 16, color: "var(--bone)" }}>
            {r.intro}
          </div>

          {r.sections.map((s) => (
            <div key={s.h} style={{ marginBottom: 22 }}>
              <div className="hm-display" style={{ fontSize: 13, color: "var(--olive)", borderBottom: "1px solid var(--border)", paddingBottom: 6, marginBottom: 10, letterSpacing: "0.02em", textTransform: "uppercase" }}>
                {s.h}
              </div>
              <div style={{ fontSize: 14.5, lineHeight: 1.55, color: "var(--bone)" }}>{s.body}</div>
            </div>
          ))}

          {/* signature */}
          <div style={{ marginTop: 32, display: "flex", alignItems: "center", gap: 14 }}>
            <div style={{ flex: 1, borderTop: "1px solid var(--border)", paddingTop: 8 }}>
              <div className="hm-display" style={{ fontSize: 16, fontStyle: "italic", letterSpacing: "0.01em", textTransform: "none" }}>
                — Signed: D. Hausmeister
              </div>
              <div className="hm-stamp-label" style={{ color: "var(--muted-foreground)", marginTop: 2 }}>
                Berlin · 14.06.2026 · caretaker
              </div>
            </div>
            <span className="hm-stamp">Freigegeben</span>
          </div>
        </div>

        {/* right: Aushang stat block + cited */}
        <div>
          <div className="hm-aushang-frame" style={{ padding: "20px 18px 16px" }}>
            <span className="hm-aushang-label">Kennzahlen · stats</span>
            <div style={{ paddingTop: 4 }}>
              {[
                { k: "Scraps total",     v: "247" },
                { k: "On the wall",      v: "61"  },
                { k: "Purged (safety)",  v: "31"  },
                { k: "Marked boring",    v: "19"  },
                { k: "Active handles",   v: "188" },
                { k: "Median funny",     v: "5.4" },
              ].map((row, i, arr) => (
                <div key={row.k} style={{
                  display: "flex", justifyContent: "space-between", alignItems: "baseline",
                  padding: "8px 0",
                  borderBottom: i === arr.length - 1 ? "none" : "1px dashed var(--border)",
                }}>
                  <span className="hm-stamp-label" style={{ color: "var(--muted-foreground)" }}>{row.k}</span>
                  <span className="hm-display" style={{ fontSize: 18, color: "var(--bone)" }}>{row.v}</span>
                </div>
              ))}
            </div>
          </div>

          {/* cited */}
          <div style={{ marginTop: 22 }}>
            <div className="hm-stamp-label" style={{ color: "var(--muted-foreground)", marginBottom: 8 }}>
              ☞ Cited corpus
            </div>
            <ul style={{ listStyle: "none", padding: 0, margin: 0, fontSize: 12, lineHeight: 1.6 }}>
              {["umlaut-88", "kartoffel-04", "lampe-90", "muelltonne-15", "schimmel-77"].map((h) => (
                <li key={h} style={{ display: "flex", gap: 8, padding: "3px 0" }}>
                  <span className="hm-stamp-label" style={{ color: "var(--olive)" }}>→</span>
                  <span className="hm-stamp-label" style={{ fontSize: 11, color: "var(--bone)", textTransform: "none", letterSpacing: 0 }}>{h}</span>
                </li>
              ))}
            </ul>
          </div>

          {/* footnote */}
          <div className="hm-stamp-label" style={{ color: "var(--muted-foreground)", lineHeight: 1.7, marginTop: 24, fontSize: 9 }}>
            Tagesbericht generated every 2h on /wall.<br/>
            Final report: SUN 14:01. The Hausmeister leaves at 14:01.
          </div>
        </div>
      </div>
    </div>
  );
}

Object.assign(window, { ScreenWall, ScreenTagesbericht });

