import { useEffect, useRef, useState } from "react";
import TopBar from "../components/TopBar.jsx";
import TabBar from "../components/TabBar.jsx";
import { SAMPLE_CHAT } from "../data/corpus.js";

export default function Chat() {
  const [messages, setMessages] = useState(SAMPLE_CHAT);
  const [draft, setDraft] = useState("");
  const [pending, setPending] = useState(false);
  const scrollRef = useRef(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, pending]);

  const send = (e) => {
    e?.preventDefault();
    const text = draft.trim();
    if (!text) return;
    const t = new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
    setMessages((m) => [...m, { who: "you", t: `Sat ${t}`, body: text }]);
    setDraft("");
    setPending(true);
    // Stub Hausmeister reply until /ask wired up
    setTimeout(() => {
      setPending(false);
      setMessages((m) => [
        ...m,
        {
          who: "haus",
          t: `Sat ${t}`,
          body: "Na ja. The corpus is silent on that. I take this as suspicious.",
        },
      ]);
    }, 1100);
  };

  return (
    <div
      className="hm-sans"
      style={{
        background: "var(--ink)",
        color: "var(--bone)",
        display: "flex",
        flexDirection: "column",
        flex: 1,
        minHeight: 0,
      }}
    >
      <TopBar subtitle="On duty" right={<span style={{ fontSize: 10, letterSpacing: "0.12em" }}>247 scraps · sweeping</span>} />

      <div
        style={{
          padding: "12px 16px",
          borderBottom: "1px solid var(--border)",
          background: "var(--card)",
          display: "flex",
          alignItems: "center",
          gap: 12,
        }}
      >
        <div
          style={{
            width: 40,
            height: 40,
            border: "2px solid var(--olive)",
            color: "var(--olive)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontFamily: "JetBrains Mono, monospace",
            fontWeight: 800,
            fontSize: 18,
          }}
        >
          H.
        </div>
        <div style={{ flex: 1 }}>
          <div className="hm-display" style={{ fontSize: 14, color: "var(--bone)" }}>
            der_hausmeister
