import { useEffect, useRef, useState } from "react";
import TopBar from "../components/TopBar.jsx";
import TabBar from "../components/TabBar.jsx";
import { SAMPLE_CHAT } from "../data/corpus.js";

export default function Chat() {
  const [messages, setMessages] = useState(SAMPLE_CHAT);
  const [draft, setDraft] = useState("");
  const [pending, setPending] = useState(false);
  const scrollRef = useRef(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, pending]);

  const send = (e) => {
    e?.preventDefault();
    const text = draft.trim();
    if (!text) return;
    const t = new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
    setMessages((m) => [...m, { who: "you", t: `Sat ${t}`, body: text }]);
    setDraft("");
    setPending(true);
    // Stub Hausmeister reply until /ask wired up
    setTimeout(() => {
      setPending(false);
      setMessages((m) => [
        ...m,
        {
          who: "haus",
          t: `Sat ${t}`,
          body: "Na ja. The corpus is silent on that. I take this as suspicious.",
        },
      ]);
    }, 1100);
  };

